/// <summary>
/// Business event class for ETG DMS Revere Integration.
/// Sends the event using the provided contract data.
/// </summary>
[BusinessEvents(classStr(ETGDMSRevereSalesAgreementIntegrationContract),
"ETG DMS Agreemnet Reverse Integration ",
    "This  business event will trigger when agreement confirmation /returnorder/Invoce",
    ModuleAxapta::General)]
internal final class ETGDMSRevereSalesAgreementIntegrationEventClass extends BusinessEventsBase
{
    private ETGDMSRevereSalesAgreementIntegrationContract contract;


}

Method.Source:
public static ETGDMSRevereSalesAgreementIntegrationEventClass newFromContract(ETGDMSRevereSalesAgreementIntegrationContract _contract)
{
    ETGDMSRevereSalesAgreementIntegrationEventClass event = new ETGDMSRevereSalesAgreementIntegrationEventClass();
    event.parmDataContract(_contract);
    return event;
}

public ETGDMSRevereSalesAgreementIntegrationContract parmDataContract( ETGDMSRevereSalesAgreementIntegrationContract _contract = contract)
{
    contract = _contract;
    return contract;
}
